solutions.javascript:
// Solution
function calculate<T>(arr: T[]): string | number {
  let sum = 0;
  let error = false;
  arr.forEach(element => {
    if (typeof element === 'number') {
      sum += element;
    } else {
      error = true;
    }
  });
  return error ? 'Error: Input array contains non-numeric values.' : sum;
}

// Example usage
console.log(calculate([1, 2, 3, 4, 5])); // 15
console.log(calculate([1, 2, 'hello', 3, 'world'])); // 'Error: Input array contains non-numeric values.'
